# type: ignore

import os

import cv2
import numpy as np
from geosat.image import image_processing as ip

from geosat.cloud.bounding_image import BoundingImage


class ProjectionImage(BoundingImage):
    def __init__(self, bounding_image, image=None):
        super().__init__(
            bounding_image.min,
            bounding_image.max,
            bounding_image.k,
            bounding_image.axisWidth,
            bounding_image.axisHeight,
            bounding_image.axisDepth,
        )
        shape = self.width, self.height
        if image is None:
            image = np.zeros(shape, dtype=np.uint8)
        elif image.shape != shape:
            raise ValueError(
                "image has an invalid shape. Expected", shape, ", received", image.shape
            )
        self.image = image

    def crop_image(self, bounding_image):
        image = np.zeros((bounding_image.width, bounding_image.height), np.uint8)
        begin = np.array(bounding_image.GetCoordinates(self.min))
        end = np.add(bounding_image.GetCoordinates(self.max), (1, 1))
        shape = tuple(end - begin)
        return ip.crop(
            cv2.resize(self.image, shape[::-1], interpolation=cv2.INTER_NEAREST),
            begin,
            image.shape,
        )

    def __add__(self, other):
        bounding_image = BoundingImage.__add__(self, other)
        self_image = self.crop_image(bounding_image)
        other_image = other.crop_image(bounding_image)
        return ProjectionImage(
            bounding_image, np.max([self_image, other_image], axis=0)
        )

    def save(self, file_path):
        config_path, image_path = ProjectionImage.get_paths(file_path)
        self.save_config(config_path)
        cv2.imwrite(image_path, self.image)

    @classmethod
    def open(cls, path, mode=cv2.IMREAD_GRAYSCALE):
        config_path, image_path = cls.get_paths(path)
        image = cv2.imread(image_path, mode)
        bounding_image = BoundingImage.open(config_path)
        return cls(bounding_image, image)

    @classmethod
    def get_image_path(cls, file_path):
        return os.path.splitext(file_path)[0] + ".png"

    @classmethod
    def get_paths(cls, file_path):
        return cls.get_config_path(file_path), cls.get_image_path(file_path)

    @classmethod
    def crop(cls, projection_image, bounding_image):
        return cls(bounding_image, projection_image.crop_image(bounding_image))

    @classmethod
    def conditional_dilation(
        cls, projection_image, kernel, nearby_projection_images=()
    ):
        global_projection_image = sum(nearby_projection_images) + projection_image
        positionned_projection_image = cls(global_projection_image) + projection_image
        image = ip.conditional_dilation(
            positionned_projection_image.image, kernel, global_projection_image.image
        )
        return cls(global_projection_image, image)
